declare(strict_types=1);

require __DIR__ . '/../includes/supabase.php';

$url      = rtrim((string) getenv('SUPABASE_URL'), '/');
$key      = (string) getenv('SUPABASE_SERVICE_ROLE_KEY');
$schema   = (string) (getenv('SUPABASE_SCHEMA') ?: 'public');
$caBundle = __DIR__ . '/../certs/cacert.pem';

if ($url === '' || $key === '') {
    fwrite(STDERR, "Faltan SUPABASE_URL o SUPABASE_SERVICE_ROLE_KEY en .env\n");
    exit(1);
}

function sb(string $method, string $path, mixed $body = null): array {
    global $url, $key, $schema, $caBundle;
    $ch = curl_init($url . $path);
    $headers = [
        'apikey: ' . $key,
        'Authorization: Bearer ' . $key,
        'Content-Type: application/json',
        'Accept: application/json',
        'Content-Profile: ' . $schema,
        'Prefer: return=minimal',
    ];
    $opts = [
        CURLOPT_RETURNTRANSFER => true,
        CURLOPT_CUSTOMREQUEST  => $method,
        CURLOPT_HTTPHEADER     => $headers,
        CURLOPT_TIMEOUT        => 30,
    ];
    if ($body !== null) {
        $opts[CURLOPT_POSTFIELDS] = is_string($body) ? $body : json_encode($body, JSON_UNESCAPED_UNICODE);
    }
    if (is_file($caBundle)) $opts[CURLOPT_CAINFO] = $caBundle;
    curl_setopt_array($ch, $opts);
    $resp   = curl_exec($ch);
    $status = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);
    return [$status, (string) $resp];
}

function stats(string $a, string $b, string $c): array {
    return [
        ['label' => 'Usuarios potenciales', 'value' => $a],
        ['label' => 'Crecimiento mercado',  'value' => $b],
        ['label' => 'Rating esperado',      'value' => $c],
    ];
}
function details(string $mercado, string $modelo, string $retorno, string $tech): array {
    return [
        ['label' => 'Mercado', 'value' => $mercado, 'icon' => 'globe'],
        ['label' => 'Modelo',  'value' => $modelo,  'icon' => 'layout'],
        ['label' => 'Retorno', 'value' => $retorno, 'icon' => 'trending-up'],
        ['label' => 'Tech',    'value' => $tech,    'icon' => 'database'],
    ];
}
